import React, { useState, useEffect, useCallback } from 'react';
import * as XLSX from 'xlsx';
import {
  getScrapEntries,
  getScrapPartySummary,
  createScrapEntry,
  overrideScrapEntry,
} from '../api';
import { adToBS as adToBSRaw, bsToADString } from '../nepaliDate';

// ─── BS/AD conversion helpers (using your nepaliDate.js) ────────────────────
// adDateStr: 'YYYY-MM-DD' → returns DD/MM/YYYY string for display/storage
function adToBSString(adDateStr) {
  if (!adDateStr) return '';
  const bs = adToBSRaw(adDateStr);
  if (!bs) return '';
  return `${String(bs.day).padStart(2,'0')}/${String(bs.month).padStart(2,'0')}/${bs.year}`;
}

// bsStr: DD/MM/YYYY string → returns 'YYYY-MM-DD' AD string
function bsStringToAD(bsStr) {
  if (!bsStr) return '';
  // strip slashes for parsing
  const clean = bsStr.replace(/\//g, '');
  if (clean.length < 8) return '';
  const day   = parseInt(clean.substring(0, 2));
  const month = parseInt(clean.substring(2, 4));
  const year  = parseInt(clean.substring(4, 8));
  if (!day || !month || !year) return '';
  return bsToADString(year, month, day) || '';
}

// ─── Number formatting ───────────────────────────────────────────────────────
const fmt = (n) => n != null && n !== '' ? parseFloat(n).toLocaleString('en-IN', { minimumFractionDigits: 2, maximumFractionDigits: 2 }) : '—';
const fmtN = (n) => n != null && n !== '' ? parseFloat(n).toLocaleString('en-IN', { minimumFractionDigits: 0, maximumFractionDigits: 2 }) : '—';

// ─── Net payable calculation (frontend mirror of backend) ───────────────────
function calcNetPayable(row) {
  const bw = parseFloat(row.bill_weight) || 0;
  const br = parseFloat(row.bill_rate) || 0;
  const ow = parseFloat(row.our_weight) || 0;
  const mo = parseFloat(row.moisture) || 0;
  const rej = parseFloat(row.rejection) || 0;
  const sr = row.superseded_rate != null ? parseFloat(row.superseded_rate) : null;
  const srej = row.superseded_rejection != null ? parseFloat(row.superseded_rejection) : null;

  const shortage = bw - ow;
  const vat = bw * br * 0.13;
  const effectiveRate = sr !== null ? sr : br;
  const effectiveTotalLab = srej !== null ? (mo + srej) : (mo + rej);

  return (bw - shortage) * effectiveRate + vat - (bw * br * effectiveTotalLab / 100);
}

// ─── Empty form state ────────────────────────────────────────────────────────
const emptyForm = {
  unloading_date_ad: '', unloading_date_bs: '',
  gen: '', grn: '',
  source: '', vehicle_no: '', party_bill_no: '',
  bill_weight: '', bill_rate: '',
  our_weight: '',
  moisture: '', rejection: '',
  scrap_tax_birgunj: '', scrap_tax_simra: '', scrap_tax_hetauda: '',
  other_expenses: '', freight: '',
};

// ════════════════════════════════════════════════════════════════════════════
export default function ScrapManagement() {
  const [activeTab, setActiveTab] = useState('form'); // 'form' | 'daily' | 'party'
  const [entries, setEntries] = useState([]);
  const [partySummary, setPartySummary] = useState([]);
  const [loading, setLoading] = useState(false);
  const [form, setForm] = useState(emptyForm);
  const [submitting, setSubmitting] = useState(false);
  const [submitMsg, setSubmitMsg] = useState(null);
  const [overrideModal, setOverrideModal] = useState(null); // { row, superseded_rate, superseded_rejection }
  const [editModal, setEditModal] = useState(null);

  // Derived calculated values for the form preview
  const amount = (parseFloat(form.bill_weight) || 0) * (parseFloat(form.bill_rate) || 0);
  const vat = amount * 0.13;
  const total = amount + vat;
  const shortage = (parseFloat(form.bill_weight) || 0) - (parseFloat(form.our_weight) || 0);
  const totalLabReport = (parseFloat(form.moisture) || 0) + (parseFloat(form.rejection) || 0);

  // ── Fetch data ──────────────────────────────────────────────────────────
  const fetchEntries = useCallback(async () => {
    setLoading(true);
    try {
      const data = await getScrapEntries();
      setEntries(data);
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  }, []);

  const fetchPartySummary = useCallback(async () => {
    setLoading(true);
    try {
      const data = await getScrapPartySummary();
      setPartySummary(data);
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    if (activeTab === 'daily') fetchEntries();
    if (activeTab === 'party') fetchPartySummary();
  }, [activeTab, fetchEntries, fetchPartySummary]);

  // ── Form handlers ───────────────────────────────────────────────────────
  const handleChange = (field, value) => {
    setForm(prev => {
      const next = { ...prev, [field]: value };
      // AD → BS auto convert
      if (field === 'unloading_date_ad' && value) {
        next.unloading_date_bs = adToBSString(value);
      }
      // BS → AD auto convert (DD/MM/YYYY = 10 chars)
      if (field === 'unloading_date_bs') {
        // auto-insert slashes
        const digits = value.replace(/\D/g, '');
        let formatted = digits;
        if (digits.length > 2) formatted = digits.slice(0,2) + '/' + digits.slice(2);
        if (digits.length > 4) formatted = digits.slice(0,2) + '/' + digits.slice(2,4) + '/' + digits.slice(4,8);
        next.unloading_date_bs = formatted;
        if (digits.length === 8) {
          const ad = bsStringToAD(formatted);
          if (ad) next.unloading_date_ad = ad;
        }
      }
      return next;
    });
  };

  const handleSubmit = async () => {
    if (!form.source) return setSubmitMsg({ type: 'error', text: 'Source (Party Name) is required.' });
    if (!form.unloading_date_ad) return setSubmitMsg({ type: 'error', text: 'Unloading date is required.' });
    if (!form.unloading_date_bs) return setSubmitMsg({ type: 'error', text: 'BS date is required.' });

    setSubmitting(true);
    setSubmitMsg(null);
    try {
      await createScrapEntry(form);
      setForm(emptyForm);
      setSubmitMsg({ type: 'success', text: 'Entry saved successfully!' });
    } catch (e) {
      setSubmitMsg({ type: 'error', text: e.response?.data?.error || 'Failed to save entry.' });
    } finally {
      setSubmitting(false);
    }
  };

  // ── Override modal handlers ─────────────────────────────────────────────
  const openOverride = (row) => {
    setOverrideModal({
      row,
      superseded_rate: row.superseded_rate ?? '',
      superseded_rejection: row.superseded_rejection ?? '',
    });
  };

  const saveOverride = async () => {
    try {
      await overrideScrapEntry(overrideModal.row.id, {
        superseded_rate: overrideModal.superseded_rate !== '' ? overrideModal.superseded_rate : null,
        superseded_rejection: overrideModal.superseded_rejection !== '' ? overrideModal.superseded_rejection : null,
      });
      setOverrideModal(null);
      fetchEntries();
    } catch (e) {
      alert('Failed to save override: ' + (e.response?.data?.error || e.message));
    }
  };

  // ── Excel export ────────────────────────────────────────────────────────
  const exportDailyExcel = () => {
    const rows = entries.map(r => ({
      'Date (AD)': r.unloading_date_ad,
      'Date (BS)': r.unloading_date_bs,
      'GEN': r.gen,
      'GRN': r.grn,
      'Party Name': r.source,
      'Vehicle No': r.vehicle_no,
      'Party Bill No': r.party_bill_no,
      'Bill Weight': r.bill_weight,
      'Bill Rate': r.bill_rate,
      'Amount': r.amount,
      'VAT': r.vat,
      'Total': r.total,
      'Our Weight': r.our_weight,
      'Shortage': r.shortage,
      'Moisture %': r.moisture,
      'Rejection %': r.rejection,
      'Total Lab Report %': r.total_lab_report,
      'Scrap Tax Birgunj': r.scrap_tax_birgunj,
      'Scrap Tax Simra': r.scrap_tax_simra,
      'Scrap Tax Hetauda': r.scrap_tax_hetauda,
      'Other Expenses': r.other_expenses,
      'Freight': r.freight,
      'Superseded Rate': r.superseded_rate,
      'Superseded Rejection %': r.superseded_rejection,
      'Net Payable': r.net_payable,
    }));
    const ws = XLSX.utils.json_to_sheet(rows);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, 'Daily Scrap');
    XLSX.writeFile(wb, 'scrap_daily_report.xlsx');
  };

  const exportPartyExcel = () => {
    const rows = partySummary.map(r => ({
      'Party Name': r.party_name,
      'Total Entries': r.total_entries,
      'Total Bill Weight': r.total_bill_weight,
      'Total Our Weight': r.total_our_weight,
      'Total Shortage': r.total_shortage,
      'Total Bill Amount': r.total_bill_amount,
      'Total VAT': r.total_vat,
      'Total Bill Total': r.total_bill_total,
      'Avg Moisture %': parseFloat(r.avg_moisture || 0).toFixed(2),
      'Avg Rejection %': parseFloat(r.avg_rejection || 0).toFixed(2),
      'Avg Total Lab Report %': parseFloat(r.avg_total_lab_report || 0).toFixed(2),
      'Total Scrap Tax Birgunj': r.total_scrap_tax_birgunj,
      'Total Scrap Tax Simra': r.total_scrap_tax_simra,
      'Total Scrap Tax Hetauda': r.total_scrap_tax_hetauda,
      'Total Other Expenses': r.total_other_expenses,
      'Total Freight': r.total_freight,
      'Total Net Payable': r.total_net_payable,
    }));
    const ws = XLSX.utils.json_to_sheet(rows);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, 'Party Summary');
    XLSX.writeFile(wb, 'scrap_party_summary.xlsx');
