  // ════════════════════════════════════════════════════════════════════════
  return (
    <div style={{ fontFamily: 'Inter, sans-serif', color: '#1a202c' }}>

      {/* ── Tab bar ── */}
      <div style={{ display: 'flex', gap: 8, marginBottom: 24 }}>
        {[
          { key: 'form', label: '✏️ New Entry' },
          { key: 'daily', label: '📋 Daily View' },
          { key: 'party', label: '🏢 Party View' },
