        ))}
      </div>

      {/* ══════════════════════════════════════════════════════════════════
          TAB 1: NEW ENTRY FORM
      ══════════════════════════════════════════════════════════════════ */}
      {activeTab === 'form' && (
        <div style={{ maxWidth: 900, margin: '0 auto' }}>
          <h2 style={{ color: '#1a3c5e', marginBottom: 20 }}>New Scrap Entry</h2>

          {submitMsg && (
            <div style={{
