              <Field label="Total Lab Report (auto)">
                <div style={{ ...inputStyle, background: '#f7fafc', fontWeight: 600, display: 'flex', alignItems: 'center' }}>
                  {form.moisture || form.rejection ? `${fmtN(totalLabReport)}%` : '—'}
