              </Field>
            </div>
          </Section>

          {/* Section 7: Taxes & Expenses */}
          <Section title="7. Taxes & Expenses">
            <div style={gridStyle(3)}>
              <Field label="Scrap Tax – Birgunj MNP">
                <input type="number" value={form.scrap_tax_birgunj}
                  onChange={e => handleChange('scrap_tax_birgunj', e.target.value)} style={inputStyle} placeholder="0" />
              </Field>
              <Field label="Scrap Tax – Simra MNP">
                <input type="number" value={form.scrap_tax_simra}
                  onChange={e => handleChange('scrap_tax_simra', e.target.value)} style={inputStyle} placeholder="0" />
