              <Field label="Scrap Tax – Hetauda MNP">
                <input type="number" value={form.scrap_tax_hetauda}
                  onChange={e => handleChange('scrap_tax_hetauda', e.target.value)} style={inputStyle} placeholder="0" />
              </Field>
              <Field label="Other Expenses">
                <input type="number" value={form.other_expenses}
                  onChange={e => handleChange('other_expenses', e.target.value)} style={inputStyle} placeholder="0" />
              </Field>
              <Field label="Freight">
                <input type="number" value={form.freight}
                  onChange={e => handleChange('freight', e.target.value)} style={inputStyle} placeholder="0" />
              </Field>
            </div>
          </Section>

          <button onClick={handleSubmit} disabled={submitting} style={{
            marginTop: 8, padding: '12px 32px', background: '#1a3c5e', color: '#fff',
            border: 'none', borderRadius: 8, fontSize: 15, fontWeight: 700,
            cursor: submitting ? 'not-allowed' : 'pointer', opacity: submitting ? 0.7 : 1,
          }}>
            {submitting ? 'Saving…' : '💾 Save Entry'}
          </button>
        </div>
      )}

      {/* ══════════════════════════════════════════════════════════════════
          TAB 2: DAILY VIEW
      ══════════════════════════════════════════════════════════════════ */}
      {activeTab === 'daily' && (
        <div>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 16 }}>
            <h2 style={{ color: '#1a3c5e', margin: 0 }}>Daily Scrap Entries</h2>
            <button onClick={exportDailyExcel} style={exportBtnStyle}>⬇ Export Excel</button>
          </div>

          {/* Admin override legend */}
          <div style={{ marginBottom: 12, fontSize: 13, color: '#718096' }}>
            <span style={{ background: '#ebf8ff', padding: '3px 8px', borderRadius: 4, border: '1px solid #90cdf4', marginRight: 8 }}>
              🔵 Override active
            </span>
            Click <strong>Override</strong> on any row to set superseded rate / rejection.
          </div>

          {loading ? <Spinner /> : (
            <div style={{ overflowX: 'auto' }}>
              <table style={tableStyle}>
                <thead>
                  <tr style={{ background: '#1a3c5e', color: '#fff' }}>
                    {['#', 'Date AD', 'Date BS', 'GEN', 'GRN', 'Party', 'Vehicle', 'Bill No',
                      'Bill Wt', 'Bill Rate', 'Amount', 'VAT', 'Total',
                      'Our Wt', 'Shortage',
                      'Moisture%', 'Rejection%', 'Lab Total%',
                      'Tax Birgunj', 'Tax Simra', 'Tax Hetauda',
                      'Other Exp', 'Freight',
                      'Sup. Rate', 'Sup. Rej%', 'Net Payable', 'Actions'
                    ].map(h => <th key={h} style={thStyle}>{h}</th>)}
                  </tr>
                </thead>
                <tbody>
                  {entries.map((row, i) => (
                    <tr key={row.id} style={{
                      background: row.is_overridden ? '#ebf8ff' : (i % 2 === 0 ? '#fff' : '#f8fafc'),
                    }}>
                      <td style={tdStyle}>{row.id}</td>
                      <td style={tdStyle}>{row.unloading_date_ad}</td>
                      <td style={tdStyle}>{row.unloading_date_bs}</td>
                      <td style={tdStyle}>{row.gen || '—'}</td>
                      <td style={tdStyle}>{row.grn || '—'}</td>
                      <td style={{ ...tdStyle, maxWidth: 140, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{row.source}</td>
                      <td style={tdStyle}>{row.vehicle_no || '—'}</td>
                      <td style={tdStyle}>{row.party_bill_no || '—'}</td>
                      <td style={{ ...tdStyle, textAlign: 'right' }}>{fmtN(row.bill_weight)}</td>
                      <td style={{ ...tdStyle, textAlign: 'right' }}>{fmtN(row.bill_rate)}</td>
                      <td style={{ ...tdStyle, textAlign: 'right' }}>{fmt(row.amount)}</td>
                      <td style={{ ...tdStyle, textAlign: 'right' }}>{fmt(row.vat)}</td>
                      <td style={{ ...tdStyle, textAlign: 'right' }}>{fmt(row.total)}</td>
                      <td style={{ ...tdStyle, textAlign: 'right' }}>{fmtN(row.our_weight)}</td>
                      <td style={{
                        ...tdStyle, textAlign: 'right',
                        color: parseFloat(row.shortage) > 0 ? '#c53030' : parseFloat(row.shortage) < 0 ? '#276749' : 'inherit',
                        fontWeight: row.shortage != null ? 600 : 'normal',
                      }}>{fmtN(row.shortage)}</td>
                      <td style={{ ...tdStyle, textAlign: 'right' }}>{fmtN(row.moisture)}</td>
                      <td style={{ ...tdStyle, textAlign: 'right' }}>{fmtN(row.rejection)}</td>
                      <td style={{ ...tdStyle, textAlign: 'right' }}>{fmtN(row.total_lab_report)}</td>
                      <td style={{ ...tdStyle, textAlign: 'right' }}>{fmt(row.scrap_tax_birgunj)}</td>
                      <td style={{ ...tdStyle, textAlign: 'right' }}>{fmt(row.scrap_tax_simra)}</td>
                      <td style={{ ...tdStyle, textAlign: 'right' }}>{fmt(row.scrap_tax_hetauda)}</td>
                      <td style={{ ...tdStyle, textAlign: 'right' }}>{fmt(row.other_expenses)}</td>
                      <td style={{ ...tdStyle, textAlign: 'right' }}>{fmt(row.freight)}</td>
                      <td style={{ ...tdStyle, textAlign: 'right', color: row.superseded_rate ? '#2b6cb0' : '#a0aec0' }}>
