                      </td>
                      <td style={{ ...tdStyle, textAlign: 'right', fontWeight: 700, color: '#276749' }}>
                        NPR {fmt(row.net_payable)}
                      </td>
                      <td style={tdStyle}>
                        <button onClick={() => openOverride(row)} style={{
                          padding: '3px 10px', fontSize: 11, background: '#2b6cb0',
                          color: '#fff', border: 'none', borderRadius: 4, cursor: 'pointer',
