                  {entries.length === 0 && (
                    <tr><td colSpan={27} style={{ ...tdStyle, textAlign: 'center', color: '#a0aec0', padding: 32 }}>No entries yet.</td></tr>
                  )}
                </tbody>
              </table>
            </div>
          )}
        </div>
      )}

      {/* ══════════════════════════════════════════════════════════════════
          TAB 3: PARTY VIEW
      ══════════════════════════════════════════════════════════════════ */}
      {activeTab === 'party' && (
        <div>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 16 }}>
