          {loading ? <Spinner /> : (
            <div style={{ overflowX: 'auto' }}>
              <table style={tableStyle}>
                <thead>
                  <tr style={{ background: '#1a3c5e', color: '#fff' }}>
                    {['Party Name', 'Entries', 'Total Bill Wt', 'Total Our Wt', 'Total Shortage',
                      'Total Bill Amt', 'Total VAT', 'Total Bill Total',
                      'Avg Moisture%', 'Avg Rejection%', 'Avg Lab Total%',
                      'Tax Birgunj', 'Tax Simra', 'Tax Hetauda',
                      'Other Exp', 'Freight', 'Total Net Payable'
                    ].map(h => <th key={h} style={thStyle}>{h}</th>)}
                  </tr>
                </thead>
                <tbody>
                  {partySummary.map((row, i) => (
