                </div>
              ))}
            </div>

            {/* Override inputs */}
            <div style={{ display: 'flex', flexDirection: 'column', gap: 14 }}>
              <Field label="Superseded Rate">
                <div style={{ position: 'relative' }}>
                  <input type="number" step="0.0001"
