                    <button onClick={() => setOverrideModal(p => ({ ...p, superseded_rate: '' }))} style={{
                      position: 'absolute', right: 8, top: '50%', transform: 'translateY(-50%)',
                      fontSize: 11, color: '#e53e3e', background: '#fff5f5', border: '1px solid #fed7d7',
                      borderRadius: 4, padding: '2px 8px', cursor: 'pointer',
                    }}>Clear</button>
                  )}
                </div>
              </Field>

              <Field label="Superseded Rejection %">
                <div style={{ position: 'relative' }}>
                  <input type="number" step="0.01"
                    value={overrideModal.superseded_rejection}
                    onChange={e => setOverrideModal(p => ({ ...p, superseded_rejection: e.target.value }))}
                    style={{ ...inputStyle, paddingRight: 80 }}
                    placeholder={`Default: ${overrideModal.row.rejection}%`} />
                  {overrideModal.superseded_rejection !== '' && (
                    <button onClick={() => setOverrideModal(p => ({ ...p, superseded_rejection: '' }))} style={{
                      position: 'absolute', right: 8, top: '50%', transform: 'translateY(-50%)',
                      fontSize: 11, color: '#e53e3e', background: '#fff5f5', border: '1px solid #fed7d7',
                      borderRadius: 4, padding: '2px 8px', cursor: 'pointer',
                    }}>Clear</button>
                  )}
                </div>
              </Field>
            </div>

            {/* Net payable preview */}
            <div style={{
              marginTop: 16, background: '#f0fff4', border: '1px solid #9ae6b4',
              borderRadius: 8, padding: '12px 16px',
              display: 'flex', justifyContent: 'space-between', alignItems: 'center',
            }}>
              <span style={{ fontSize: 13, color: '#276749', fontWeight: 600 }}>Preview Net Payable</span>
              <span style={{ fontSize: 16, fontWeight: 800, color: '#276749' }}>
                NPR {fmt(calcNetPayable({
                  ...overrideModal.row,
                  superseded_rate: overrideModal.superseded_rate !== '' ? overrideModal.superseded_rate : null,
                  superseded_rejection: overrideModal.superseded_rejection !== '' ? overrideModal.superseded_rejection : null,
                }))}
              </span>
            </div>

            {/* Actions */}
            <div style={{ display: 'flex', gap: 10, marginTop: 20 }}>
              <button onClick={saveOverride} style={{
                flex: 1, padding: '11px 0', background: '#1a3c5e', color: '#fff',
                border: 'none', borderRadius: 8, fontSize: 14, fontWeight: 700, cursor: 'pointer',
              }}>Save Override</button>
              <button onClick={() => setOverrideModal(null)} style={{
                flex: 1, padding: '11px 0', background: '#fff', color: '#4a5568',
                border: '1px solid #cbd5e0', borderRadius: 8, fontSize: 14, fontWeight: 600, cursor: 'pointer',
              }}>Cancel</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

// ─── Sub-components ──────────────────────────────────────────────────────────
function Section({ title, children }) {
  return (
    <div style={{ marginBottom: 20, background: '#fff', borderRadius: 10, border: '1px solid #e2e8f0', overflow: 'hidden' }}>
      <div style={{ background: '#f7fafc', padding: '10px 16px', borderBottom: '1px solid #e2e8f0' }}>
        <span style={{ fontWeight: 700, fontSize: 13, color: '#4a5568', textTransform: 'uppercase', letterSpacing: '0.05em' }}>{title}</span>
      </div>
      <div style={{ padding: 16 }}>{children}</div>
    </div>
  );
}

function Field({ label, children, required }) {
  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: 4, marginBottom: 4 }}>
      <label style={{ fontSize: 12, fontWeight: 600, color: '#4a5568' }}>
        {label}{required && <span style={{ color: '#e53e3e' }}> *</span>}
      </label>
      {children}
    </div>
  );
}

function CalcChip({ label, value, color }) {
  return (
    <div style={{ background: '#f7fafc', border: '1px solid #e2e8f0', borderRadius: 8, padding: '6px 14px', fontSize: 13 }}>
      <span style={{ color: '#718096' }}>{label}: </span>
      <span style={{ fontWeight: 700, color: color || '#2d3748' }}>{value}</span>
    </div>
  );
}

function Spinner() {
  return <div style={{ textAlign: 'center', padding: 40, color: '#a0aec0' }}>Loading…</div>;
}

